/**
 * @summary List production plans
 */
export const getListProductionPlansUrl = (
  params?: ListProductionPlansParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/production-plans?${stringifiedParams}`
    : `/api/production-plans`;
};

export const listProductionPlans = async (
  params?: ListProductionPlansParams,
  options?: RequestInit,
): Promise<ProductionPlan[]> => {
  return customFetch<ProductionPlan[]>(getListProductionPlansUrl(params), {
    ...options,
    method: "GET",
  });
};

